SELECT canc.year, canc.month, canc.reporting_airline, canc.cancellation_reason, canc.cancellation_code, canc.cancelled_flights, ROUND(100.0 * canc.cancelled_flights / NULLIF(totals.total_flights, 0), 2) AS cancellation_rate_pct, ROUND(100.0 * canc.cancelled_flights / NULLIF(totals.total_cancelled, 0), 2) AS reason_share_pct, totals.total_flights AS airline_total_flights, totals.total_cancelled AS airline_total_cancelled FROM (SELECT CAST(year AS INT) AS year, CAST(month AS INT) AS month, reporting_airline, CASE cancellationcode WHEN 'A' THEN 'Carrier' WHEN 'B' THEN 'Weather' WHEN 'C' THEN 'National Air System' WHEN 'D' THEN 'Security' ELSE 'Unknown' END AS cancellation_reason, cancellationcode AS cancellation_code, COUNT(*) AS cancelled_flights FROM silver_flights WHERE cancelled = 1 GROUP BY year, month, reporting_airline, cancellationcode) canc JOIN (SELECT CAST(year AS INT) AS year, CAST(month AS INT) AS month, reporting_airline, COUNT(*) AS total_flights, SUM(CASE WHEN cancelled = 1 THEN 1 ELSE 0 END) AS total_cancelled FROM silver_flights GROUP BY year, month, reporting_airline) totals ON canc.year = totals.year AND canc.month = totals.month AND canc.reporting_airline = totals.reporting_airline
